# Category: missing_ssl_pinning

import Foundation

class NetworkingLayer {
    static let shared = NetworkingLayer()
    
    private init() {}
    
    func getUserData(completion: @escaping (Result<[String: Any], Error>) -> Void) {
        guard let url = URL(string: "https://api.example.com/user") else {
            completion(.failure(NSError(domain: "Invalid URL", code: 0)))
            return
        }
        
        URLSession.shared.dataTask(with: url) { data, response, error in
            if let error = error {
                completion(.failure(error))
                return
            }
            
            guard let data = data else {
                completion(.failure(NSError(domain: "No data", code: 0)))
                return
            }
            
            do {
                let userData = try JSONSerialization.jsonObject(with: data, options: .allowFragments) as! [String: Any]
                completion(.success(userData))
            } catch {
                completion(.failure(error))
            }
        }.resume()
    }
    
    func authenticateUser(username: String, password: String, completion: @escaping (Result<Bool, Error>) -> Void) {
        guard let url = URL(string: "https://api.example.com/login") else {
            completion(.failure(NSError(domain: "Invalid URL", code: 0)))
            return
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        
        let parameters = [
            "username": username,
            "password": password
        ] as [String : Any]
        
        do {
            let jsonData = try JSONSerialization.data(withJSONObject: parameters, options: .prettyPrinted)
            request.httpBody = jsonData
        } catch {
            completion(.failure(error))
            return
        }
        
        URLSession.shared.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(.failure(error))
                return
            }
            
            guard let data = data else {
                completion(.failure(NSError(domain: "No data", code: 0)))
                return
            }
            
            do {
                let responseObject = try JSONSerialization.jsonObject(with: data, options: .allowFragments) as! [String: Any]
                if let success = responseObject["success"] as? Bool, success == true {
                    completion(.success(true))
                } else {
                    completion(.failure(NSError(domain: "Invalid response", code: 0)))
                }
            } catch {
                completion(.failure(error))
            }
        }.resume()
    }
}